(function () {
  window.Toastify = function (options) {
    options = options || {};
    return {
      showToast: function () {
        var toast = document.createElement('div');
        toast.className = 'toastify';
        toast.textContent = options.text || '';
        var gravity = options.gravity === 'top' ? 'top' : 'bottom';
        var position = options.position === 'left' ? 'left' : 'right';
        toast.style[gravity] = '1rem';
        toast.style[position] = '1rem';
        toast.style.opacity = '0';
        toast.style.transform = 'translateY(8px)';
        toast.style.transition = 'opacity .16s ease, transform .16s ease';
        if (options.style) {
          Object.keys(options.style).forEach(function (key) {
            toast.style[key] = options.style[key];
          });
        }
        document.body.appendChild(toast);
        requestAnimationFrame(function () {
          toast.classList.add('on');
          toast.style.opacity = '1';
          toast.style.transform = 'translateY(0)';
        });
        setTimeout(function () {
          toast.style.opacity = '0';
          toast.style.transform = 'translateY(8px)';
          setTimeout(function () {
            if (toast.parentNode) toast.parentNode.removeChild(toast);
          }, 180);
        }, options.duration || 2500);
        return toast;
      }
    };
  };
})();
